class Solution:
    def numberOfWays(self, n: int, x: int) -> int:
        MOD = 10**9 + 7
        powers = []
        i = 1
        while i ** x <= n:
            powers.append(i ** x)
            i += 1

        def backtrack(start, target):
            if target == 0:
                return 1
            if target < 0:
                return 0
            count = 0
            for i in range(start, len(powers)):
                if powers[i] > target:
                    break
                count += backtrack(i + 1, target - powers[i])
                count %= MOD
            return count

        return backtrack(0, n)
